import type { FullLesson, ReviewMetadata } from './lmsTypes'
import { getSourceById } from './sourceRegistry'

const COURSE_ID = 'systems-deployment-foundations'
const REVIEW_DATE = '2026-07-20'

interface LessonBlueprint {
  id: string
  title: string
  objective: string
  instruction: [string, string, string]
  standard: string
  controls: string[]
  failures: string[]
  scenarioTitle: string
  scenarioContext: string
  decision: string
  recommendation: string
  labTitle: string
  labBrief: string
  labSteps: string[]
  evidence: string[]
  answerGuide: string[]
  takeaways: string[]
  sourceIds: string[]
  visualTitle: string
  visualSteps: Array<{ label: string; detail: string }>
  capstoneLink: string
}

interface ModuleBlueprint {
  id: string
  title: string
  order: number
  lessons: LessonBlueprint[]
}

function reviewMetadata(sourceVersion: string, limitations: string[]): ReviewMetadata {
  return {
    contentVersion: '1.0.0',
    lastReviewed: REVIEW_DATE,
    reviewOwner: 'Orivo Academy curriculum review',
    reviewStatus: 'reviewed',
    sourceVersion,
    knownLimitations: limitations,
  }
}

function lessonSource(sourceId: string) {
  const source = getSourceById(sourceId)
  if (!source) throw new Error(`Missing registered source ${sourceId}`)
  return { sourceId, label: source.title, url: source.url, publisher: source.publisher }
}

function buildLesson(module: ModuleBlueprint, blueprint: LessonBlueprint, lessonOrder: number): FullLesson {
  const primarySource = getSourceById(blueprint.sourceIds[0])
  if (!primarySource) throw new Error(`Missing primary source ${blueprint.sourceIds[0]}`)
  return {
    id: blueprint.id,
    courseId: COURSE_ID,
    moduleId: module.id,
    moduleTitle: module.title,
    moduleOrder: module.order,
    lessonOrder,
    title: blueprint.title,
    objective: blueprint.objective,
    sections: [
      {
        heading: 'How the system behaves',
        paragraphs: blueprint.instruction,
      },
      {
        heading: 'Implementation standard',
        paragraphs: [blueprint.standard],
        bullets: blueprint.controls,
      },
      {
        heading: 'Failure patterns and evidence',
        paragraphs: ['Implementation leaders do not need to diagnose every component alone, but they must recognize evidence that narrows the failure domain and prevents unstructured escalation.'],
        bullets: blueprint.failures,
      },
      {
        heading: 'Capstone connection',
        paragraphs: [blueprint.capstoneLink],
      },
    ],
    visual: {
      title: blueprint.visualTitle,
      caption: 'Original Orivo Academy model. The sequence is a decision aid, not a vendor-specific architecture requirement.',
      steps: blueprint.visualSteps,
      sourceLabel: primarySource.title,
      sourceUrl: primarySource.url,
    },
    scenario: {
      title: blueprint.scenarioTitle,
      context: blueprint.scenarioContext,
      decision: blueprint.decision,
      recommendedApproach: blueprint.recommendation,
    },
    lab: {
      title: blueprint.labTitle,
      brief: blueprint.labBrief,
      steps: blueprint.labSteps,
      evidence: blueprint.evidence,
      answerGuide: blueprint.answerGuide,
    },
    keyTakeaways: blueprint.takeaways,
    sources: blueprint.sourceIds.map(lessonSource),
    review: reviewMetadata(
      blueprint.sourceIds.map((id) => getSourceById(id)?.version ?? getSourceById(id)?.title ?? id).join('; '),
      [
        'The course teaches implementation leadership and technical fluency, not vendor certification or infrastructure administration.',
        'Cloud interfaces, hosted runner images, pipeline plugins, and product plan availability may change.',
        'Healthcare scenarios are synthetic and do not establish regulatory compliance.',
      ],
    ),
  }
}

