        failures: ['Client testers receive access after the UAT window starts.', 'Synthetic data lacks the duplicate and date edge cases required by the test.', 'A shared administrator account prevents accountability.', 'The environment is reset without a support plan during testing.'],
        scenarioTitle: 'UAT begins with no usable test records',
